---@class StructRankFormationHeroInfo
local StructRankFormationHeroInfo = LxClass("StructRankFormationHeroInfo", nil)
LXImport(".StructHeroTreeInfo")
function StructRankFormationHeroInfo:StructRankFormationHeroInfo()
	self.id = ""
	self.index = 0
	self.refId = 0
	self.level = 0
	self.star = 0
	self.power = 0
	self.grade = 0
	self.skin = 0
	self.resonance = 0
	self.treeInfo = nil
	self.endTime = 0					-- 限时英雄，0表示永久
	self.isTry = false					-- 是否为限时英雄
	self.talentSkills = {}
	self.coreLevel = 0					-- 核心等级
	self.outfitSkill = 0
	self.sorceryCardId = 0
	self.spiritLinkId = ""
	self.sorceryCardLevel = 0
	-- self.crystalSheet = 0【G公共支持】删除伙伴晶石功能相关数据
end

function StructRankFormationHeroInfo:CreateByPb(pb)
	self.id = pb.id
	self.index = pb.index
	self.refId = pb.refId
	self.level = pb.level
	self.star = pb.star
	self.power = pb.power
	self.grade = pb.grade
	self.skin = pb.skin
	self.resonance = pb.resonance

	local treeInfo = StructHeroTreeInfo:New()
	treeInfo:CreateByPb(pb.treeInfo)
	self.treeInfo = treeInfo

	self.endTime = 0
	if pb.endTime then
		self.endTime = tonumber(pb.endTime)/1000
	end
	self.isTry = self.endTime and self.endTime > 0

	self.talentSkills = {}
	local talentSkills = pb.talentSkills or {}
	for i, v in ipairs(talentSkills) do
		if type(v) =="table" then
			local position = v.position
			local skillId = v.skillId
			self.talentSkills[position] = skillId
		end
	end
	self.coreLevel = pb.coreLevel
	self.outfitSkill = pb.outfitSkill
	self.sorceryCardId = pb.sorceryCardId
	self.spiritLinkId = pb.spiritLinkId
	self.sorceryCardLevel = pb.sorceryCardLevel
	-- self.crystalSheet = pb.crystalSheet【G公共支持】删除伙伴晶石功能相关数据
end

return StructRankFormationHeroInfo